const solutions = $('Fetch Solution Config').all().map(i => i.json);
const slaConfigs = $('Fetch SLA Configs').all().map(i => i.json);

// Build field config map keyed by solution_id
const solutionFieldConfigs = {};
const solutionByListId = {};
const solutionById = {};
for (const sol of solutions) {
  const configs = Array.isArray(sol.custom_field_configs)
    ? sol.custom_field_configs
    : (typeof sol.custom_field_configs === 'string' ? JSON.parse(sol.custom_field_configs) : []);
  const fieldMap = {};
  for (const cfg of configs) {
    fieldMap[cfg.field_key] = {
      clickup_field_id: cfg.clickup_field_id,
      options: typeof cfg.options === 'string' ? JSON.parse(cfg.options) : (cfg.options || {})
    };
  }
  solutionFieldConfigs[sol.solution_id] = fieldMap;
  solutionByListId[sol.clickup_list_id] = sol;
  solutionById[sol.solution_id] = sol;
}

// Build SLA config map: solution_id -> { priority -> {response_hours, resolution_hours} }
const slaBySolution = {};
for (const sla of slaConfigs) {
  if (!slaBySolution[sla.solution_id]) slaBySolution[sla.solution_id] = {};
  slaBySolution[sla.solution_id][sla.priority] = sla;
}

return [{
  json: {
    _solutions: solutions,
    _sla_configs: slaConfigs,
    _sla_by_solution: slaBySolution,
    _solution_field_configs: solutionFieldConfigs,
    _solution_by_list_id: solutionByListId,
    _solution_by_id: solutionById
  }
}];

const dbTickets = $input.all().map(i => i.json);
return [{
  json: {
    _db_tickets: dbTickets
  }
}];

const done = $input.all().map(i => i.json);
return [{
  json: {
    _done: done
  }
}];

const t = $input.first().json;

const levelLabels = { 1: 'Yellow Alert', 2: 'Orange Alert', 3: 'Red Alert', 4: 'Critical Breach' };
const level = t._next_escalation_level || 1;
const labelText = levelLabels[level] || 'Escalation';
const pct = t._sla_consumption || 0;

// Build AI prompt for escalation comment
const prompt = `You are a support operations AI writing a concise ClickUp escalation comment.

Ticket: ${t.title}
Priority: ${t.priority}
Current Status: ${t.status}
SLA Consumed: ${pct}%
Escalation Level: ${level} (${labelText})
Module: ${t.module || 'N/A'}
Request Type: ${t.request_type || 'N/A'}

Write a professional 2-3 sentence escalation comment for the support team. 
Be direct about urgency, current SLA position, and what action is needed.
Do NOT use placeholders or markdown headers. Output plain text only.`;

return [{
  json: {
    ...t,
    _escalation_prompt: prompt,
    _escalation_level: level,
    _escalation_label: labelText,
    _escalation_pct: pct
  }
}];

// Fetch tasks from ALL solution lists with full pagination
const solutions = $('Fetch Solution Config').all().map(i => i.json);
const TOKEN = 'pk_93735320_XU6SZJQGN677F46481KDAUGANNZU1GOT';
const BASE = 'https://api.clickup.com/api/v2';

const allTasks = [];
const listMeta = {};

for (const sol of solutions) {
  const listId = sol.clickup_list_id;
  if (!listId) continue;
  listMeta[listId] = sol;

  let page = 0;
  let lastPage = false;

  while (!lastPage) {
    const url = `${BASE}/list/${listId}/task?archived=false&include_closed=true&subtasks=true&page=${page}`;
    const resp = await $helpers.httpRequest({
      method: 'GET',
      url,
      headers: { Authorization: TOKEN }
    });

    const tasks = resp.tasks || [];
    // Tag each task with its list_id so Compare & Classify can resolve solution
    for (const t of tasks) {
      t._source_list_id = listId;
      t._solution_id = sol.solution_id;
    }
    allTasks.push(...tasks);

    lastPage = resp.last_page !== false ? true : false;
    if (tasks.length < 100) lastPage = true; // ClickUp returns max 100/page
    page++;
    if (page > 20) break; // safety cap — 2000 tasks max
  }
}

return [{ json: { _all_tasks: allTasks, _list_meta: listMeta } }];

const ticket = $input.first().json;
const TOKEN = 'pk_93735320_XU6SZJQGN677F46481KDAUGANNZU1GOT';
const listId = ticket._list_id;
if (!listId) return [{ json: { ...ticket, _push_result: 'no_list_id' } }];

const fieldConfig = ticket._field_config || {};

// Build custom fields array from fieldConfig
function resolveOption(fieldKey, optionName) {
  const cfg = fieldConfig[fieldKey];
  if (!cfg) return null;
  return cfg.options?.[optionName] || null;
}

const customFields = [];
const rtId = fieldConfig['request_type']?.clickup_field_id;
const rtOpt = resolveOption('request_type', ticket.request_type);
if (rtId && rtOpt) customFields.push({ id: rtId, value: rtOpt });

const ctId = fieldConfig['case_type']?.clickup_field_id;
const ctOpt = resolveOption('case_type', ticket.case_type);
if (ctId && ctOpt) customFields.push({ id: ctId, value: ctOpt });

const srcId = fieldConfig['source']?.clickup_field_id;
const srcOpt = resolveOption('source', ticket.channel || 'apex');
if (srcId && srcOpt) customFields.push({ id: srcId, value: srcOpt });

const PMAP = { P1: 1, P2: 2, P3: 3, P4: 4, P5: 4 };
const SMAP = { 'open':'open','in progress':'in progress','on hold':'on hold','resolved':'complete','closed':'complete' };

const body = {
  name: `ticketNo-${ticket.ticket_id} | ${(ticket.title||'').substring(0,80)}`,
  description: ticket.description || '',
  priority: PMAP[ticket.priority] || 3,
  status: SMAP[ticket.status?.toLowerCase()] || 'open',
  assignees: [87796566],
  ...(customFields.length > 0 ? { custom_fields: customFields } : {})
};

try {
  const resp = await $helpers.httpRequest({
    method: 'POST',
    url: `https://api.clickup.com/api/v2/list/${listId}/task`,
    headers: { Authorization: TOKEN, 'Content-Type': 'application/json' },
    body
  });
  return [{ json: { ...ticket, _new_clickup_task_id: resp.id, _new_clickup_url: resp.url, _push_result: 'ok' } }];
} catch(e) {
  return [{ json: { ...ticket, _push_result: 'error', _push_error: e.message } }];
}
